def shortest_after_removal(s):
    def remove_abcd(s, target):
        while target in s:
            s = s.replace(target, "")
        return s

    # Remove 'AB' first, then continue removing 'AB' or 'CD'
    s1 = remove_abcd(remove_abcd(s, "AB"), "CD")

    # Remove 'CD' first, then continue removing 'AB' or 'CD'
    s2 = remove_abcd(remove_abcd(s, "CD"), "AB")

    # Return the length of the shorter resulting string
    return min(len(s1), len(s2))

