def min_leftover_chars(s, word_dict):
    from functools import lru_cache

    # Convert word_dict to a set for faster lookup
    word_set = set(word_dict)

    @lru_cache(maxsize=None)
    def dp(start):
        if start == len(s):
            return 0
        min_leftover = len(s) - start  # Initialize with maximum possible value

        for end in range(start + 1, len(s) + 1):
            if s[start:end] in word_set:
                leftover = dp(end)
                min_leftover = min(min_leftover, leftover)

        return min_leftover

    result = dp(0)
    return result

