    def factorial(x):
        return x * factorial(x - 1) if x else 1

    def sum_up_to_i(i):
        return sum(range(1, i + 1))

    result = []
    for i in range(1, n + 1):
        if i % 2 == 0:
            result.append(factorial(i - 1))
        else:
            result.append(sum_up_to_i(i))
    return result

