def create_list(n):
    def factorial(i):
        if i == 0 or i == 1: return 1
        return i * factorial(i - 1)

    result = []
    for i in range(1, n + 1):
        if i % 2 == 0:
            result.append(factorial(i))
        else:
            result.append(sum(range(1, i + 1)))
    return result
